args.command:
result=$(curl -ksS -o /dev/null -w "HTTP_STATUS:%{http_code}
REMOTE_IP:%{remote_ip}
TIME_TOTAL:%{time_total}s
" --max-time 10 https://1.1.1.1); echo "$result"; if echo "$result" | grep -q "HTTP_STATUS:000"; then exit 1; fi

if ping -c 3 -W 2 192.168.1.2; then echo "LAN_REACHABLE:true"; else echo "LAN_REACHABLE:false"; fi; result=$(curl -ksS -o /dev/null -w "HTTP_STATUS:%{http_code}
REMOTE_IP:%{remote_ip}
TIME_TOTAL:%{time_total}s
" --max-time 10 https://1.1.1.1); echo "$result"; iptables -L OUTPUT -n --line-numbers
